import { Injectable, signal, computed, inject, DOCUMENT } from '@angular/core';

import { DISPLAY_MODE_KEY } from '../constants';
import { DisplayMode } from '../enums';

@Injectable({ providedIn: 'root' })
export class ThemeService {
  private currentDisplayMode = signal<DisplayMode>(DisplayMode.LIGHT_MODE);
  private document = inject(DOCUMENT);

  public isDark = computed(() => this.currentDisplayMode() === DisplayMode.DARK_MODE);

  /**
   * Load theme from storage or use default
   */
  public loadDisplayMode(): void {
    const storageDisplayMode = localStorage.getItem(DISPLAY_MODE_KEY) ?? '';
    if (storageDisplayMode && this.isValidDisplayMode(storageDisplayMode)) {
      this.applyDisplayMode(storageDisplayMode);
    } else {
      this.applyDisplayMode(DisplayMode.LIGHT_MODE);
    }
  }

  /**
   * Check if theme name is valid
   */
  private isValidDisplayMode(displayMode: string): displayMode is DisplayMode {
    return Object.values(DisplayMode).includes(displayMode as DisplayMode);
  }

  /**
   * Apply theme by switching the stylesheet bundle and CSS classes
   */
  public applyDisplayMode(displayMode: DisplayMode): void {
    if (!this.isValidDisplayMode(displayMode)) {
      console.warn(`Invalid display mode: ${displayMode}`);
      return;
    }

    const htmlElement = this.document.querySelector('html');
    htmlElement?.classList.remove(DisplayMode.DARK_MODE);
    htmlElement?.classList.remove(DisplayMode.LIGHT_MODE);
    htmlElement?.classList.add(displayMode);

    // Store the theme in the storage
    localStorage.setItem(DISPLAY_MODE_KEY, displayMode);

    console.log(`Display mode applied: ${displayMode}`);

    this.currentDisplayMode.set(displayMode);
  }

  /**
   * Toggle between light and dark themes
   */
  public toggleDisplayMode(): void {
    const newDisplayMode =
      this.currentDisplayMode() === DisplayMode.LIGHT_MODE
        ? DisplayMode.DARK_MODE
        : DisplayMode.LIGHT_MODE;
    this.applyDisplayMode(newDisplayMode);
  }

  /**
   * Set light theme
   */
  public applyLightDisplayMode(): void {
    this.applyDisplayMode(DisplayMode.LIGHT_MODE);
  }

  /**
   * Set dark theme
   */
  public applyDarkDisplayMode(): void {
    this.applyDisplayMode(DisplayMode.DARK_MODE);
  }
}
