import { Directive, TemplateRef, input } from '@angular/core';

/**
 * Permite sobrescribir el render de una celda para una columna (por `column.key`),
 * ignorando el `type` de la columna.
 *
 * Uso:
 * `<ng-template bodDataTableCell="items" let-row let-column="column"> ... </ng-template>`
 */
@Directive({
  selector: 'ng-template[bodDataTableCell]',
  standalone: true,
})
export class DataTableCellTemplateDirective<T = unknown> {
  public readonly bodDataTableCell = input.required<string>();

  public constructor(public readonly templateRef: TemplateRef<T>) {}
}

