import { Injectable, inject, signal, PLATFORM_ID, effect } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

/**
 * Tailwind breakpoints (px):
 * sm: 640, md: 768, lg: 1024, xl: 1280, 2xl: 1536
 */
export const VIEWPORT_BREAKPOINTS = {
  sm: 640,
  md: 768,
  lg: 1024,
  xl: 1280,
  '2xl': 1536,
} as const;

export type ViewportBreakpoint = keyof typeof VIEWPORT_BREAKPOINTS;

@Injectable({ providedIn: 'root' })
export class ViewportService {
  private readonly platformId = inject(PLATFORM_ID);

  private readonly _width = signal(0);
  private readonly _height = signal(0);

  /** Current viewport width in pixels */
  public readonly width = this._width.asReadonly();

  /** Current viewport height in pixels */
  public readonly height = this._height.asReadonly();

  /** Whether viewport is below lg breakpoint (1024px) - use drawer instead of fixed sidebar */
  public readonly isMobileView = signal(false);

  public constructor() {
    effect(() => {
      if (!isPlatformBrowser(this.platformId)) return;

      this.updateViewport();

      const handler = () => this.updateViewport();
      window.addEventListener('resize', handler);

      return () => window.removeEventListener('resize', handler);
    });
  }

  /** Check if viewport is below a specific breakpoint */
  public isBelow(breakpoint: ViewportBreakpoint): boolean {
    const threshold = VIEWPORT_BREAKPOINTS[breakpoint];
    return this._width() < threshold;
  }

  /** Check if viewport is at or above a specific breakpoint */
  public isAtOrAbove(breakpoint: ViewportBreakpoint): boolean {
    return !this.isBelow(breakpoint);
  }

  private readonly updateViewport = (): void => {
    const w = window.innerWidth;
    this._width.set(w);
    this._height.set(window.innerHeight);
    this.isMobileView.set(w < VIEWPORT_BREAKPOINTS.lg);
  };
}
