import { ChangeDetectionStrategy, Component, computed, input } from '@angular/core';
import { TranslateModule } from '@ngx-translate/core';
import { LoadingIndicator } from '../loading-indicator/loading-indicator';
import { Message } from 'primeng/message';
import { NgTemplateOutlet } from '@angular/common';
import { Button } from 'primeng/button';
import { LoadState } from '../../../enums';

@Component({
  selector: 'bod-load-state-handler',
  imports: [TranslateModule, LoadingIndicator, Message, NgTemplateOutlet, Button],
  templateUrl: './load-state-handler.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  styles: `
    ::ng-deep .p-message-text {
      width: 100%;
    }
  `,
})
export class LoadStateHandler {
  public readonly loadState = input.required<LoadState>();

  public readonly retryFn = input<() => void>();
  public readonly backFn = input<() => void>();

  public readonly emptyText = input<string>('common.empty');
  public readonly errorText = input<string>('common.error');
  public readonly loadingText = input<string>('common.loading');
  public readonly goBackText = input<string>('common.goBack');
  public readonly retryText = input<string>('common.retry');

  protected readonly isLoading = computed(() => this.loadState() === LoadState.LOADING);
  protected readonly isSuccess = computed(() => this.loadState() === LoadState.SUCCESS);
  protected readonly isError = computed(() => this.loadState() === LoadState.ERROR);
  protected readonly isEmpty = computed(() => this.loadState() === LoadState.EMPTY);

  public readonly display = input<'simple' | 'full'>('simple');

  public readonly onRetry = () => {
    this.retryFn()?.();
  };

  public readonly onBack = () => {
    this.backFn()?.();
  };
}
