import { ChangeDetectorRef, DestroyRef, inject, Pipe, PipeTransform } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { TranslateService } from '@ngx-translate/core';

@Pipe({
  name: 'localizedKeys',
  standalone: true,
  pure: false,
})
export class LocalizedKeysPipe implements PipeTransform {
  private readonly translateService = inject(TranslateService);
  private readonly changeDetectorRef = inject(ChangeDetectorRef);
  private readonly destroyRef = inject(DestroyRef);

  constructor() {
    this.translateService.onLangChange
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(() => this.changeDetectorRef.markForCheck());
  }

  /**
   * Localizes only the given keys when their value is a string (treated as translation key).
   * When `deep` is true, recurses into nested objects and arrays and applies the same keys.
   *
   * @param value - A single object, an array of objects, or null/undefined
   * @param keys - Keys to translate (e.g. ['label', 'title']). Only these properties are translated, and only if their value is a string.
   * @param deep - If true, recurse into nested objects and arrays
   * @returns The same structure with translated values for the given keys when value is string
   */
  public transform<T>(value: T, keys: string[], deep = false): T {
    if (value === null || value === undefined) {
      return value;
    }
    if (!Array.isArray(keys) || keys.length === 0) {
      return value;
    }
    const keysSet = new Set(keys);
    return this.localize(value, keysSet, deep) as T;
  }

  private localize(value: unknown, keys: Set<string>, deep: boolean): unknown {
    if (typeof value === 'string') {
      return this.translateService.instant(value);
    }
    if (Array.isArray(value)) {
      if (!deep) return value;
      return value.map((item) => this.localize(item, keys, deep));
    }
    if (
      typeof value === 'object' &&
      value !== null &&
      !Array.isArray(value) &&
      this.isPlainObject(value)
    ) {
      const obj = value as Record<string, unknown>;
      const result: Record<string, unknown> = {};
      for (const [key, val] of Object.entries(obj)) {
        if (keys.has(key) && typeof val === 'string') {
          result[key] = this.translateService.instant(val);
        } else if (deep && typeof val === 'object' && val !== null) {
          result[key] = this.localize(val, keys, deep);
        } else {
          result[key] = val;
        }
      }
      return result;
    }
    return value;
  }

  private isPlainObject(value: object): boolean {
    return Object.prototype.toString.call(value) === '[object Object]';
  }
}
