import { ChangeDetectionStrategy, Component, DestroyRef, inject, OnInit, computed, input, output } from '@angular/core';
import { InputTextModule } from 'primeng/inputtext';
import { IconFieldModule } from 'primeng/iconfield';
import { InputIconModule } from 'primeng/inputicon';
import { TranslateModule } from '@ngx-translate/core';
import { FormsModule } from '@angular/forms';
import { PopoverModule } from 'primeng/popover';
import { Button } from 'primeng/button';
import { ListboxModule } from 'primeng/listbox';
import { InputGroupModule } from 'primeng/inputgroup';
import { InputGroupAddonModule } from 'primeng/inputgroupaddon';
import { MenuModule } from 'primeng/menu';
import { MenuItem } from 'primeng/api';
import { CheckboxModule } from 'primeng/checkbox';
import { Subject } from 'rxjs';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { debounceTime } from 'rxjs/operators';
import { FormField } from '../form-field/form-field';
import { FormFieldControl } from '../form-field/form-field-control';
import { TemplateRef } from '@angular/core';
import { PaginatedVista } from '../../../models/paginated-vistas';
import { SelectModule } from 'primeng/select';

export interface Column<TKey extends string = string> {
  key: TKey;
  field?: string;
  header: string;
  template?: TemplateRef<unknown>;
}

@Component({
  selector: 'bod-table-toolbar',
  imports: [
    FormsModule,
    IconFieldModule,
    InputTextModule,
    TranslateModule,
    InputIconModule,
    PopoverModule,
    Button,
    ListboxModule,
    InputGroupModule,
    InputGroupAddonModule,
    FormFieldControl,
    FormField,
    CheckboxModule,
    MenuModule,
    SelectModule,
  ],
  templateUrl: './table-toolbar.html',
  styleUrl: './table-toolbar.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class TableToolbar implements OnInit {
  public actionsMenuItems = input<MenuItem[]>([]);
  public displayedColumns = input<string[]>([]);
  public vistas = input<PaginatedVista[]>([]);
  public displayedColumnsChange = output<string[]>();
  public title = input<string>('');
  public columns = input<Column[]>([]);
  public searchChange = output<string>();
  public selectedVista = input<string | null>(null);
  public selectedVistaChange = output<string>();
  private destroyRef = inject(DestroyRef);
  protected searchInput = new Subject<string>();

  private _displayedColumnsSet = computed(() => new Set(this.displayedColumns()));

  public ngOnInit(): void {
    this.searchInput.pipe(takeUntilDestroyed(this.destroyRef), debounceTime(500)).subscribe((value) => {
      this.searchChange.emit(value);
    });
  }

  public columnIsChecked(columnKey: string) {
    return this._displayedColumnsSet().has(columnKey);
  }

  public onColumnChecked(columnKey: string) {
    if (this._displayedColumnsSet().has(columnKey)) {
      this.displayedColumnsChange.emit(this.displayedColumns().filter((c) => c !== columnKey));
    } else {
      this.displayedColumnsChange.emit([...this._displayedColumnsSet(), columnKey]);
    }
  }
}
