export class Endpoint {
  constructor(
    public readonly path: string,
    public readonly method: 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH' | 'OPTIONS' | 'HEAD',
    public readonly baseUrl: string,
    public readonly version?: 'v1' | 'v2' | 'v3',
  ) {}

  public toString(): string {
    return `${this.baseUrl}/${this.version ? `${this.version}/` : ''}${this.path}`;
  }
}
