import { concatMap, map, Observable, throwError } from 'rxjs';
import { DataSourcePaginator } from './data-source-paginator';
import { PaginatedVista, Pagination } from '../models';
import { PaginatedVistaColumn } from '../models';
import { PaginationRequest } from '../models';

export class DataTableBuilder<T extends object> {
  private readonly fetchVistas: () => Observable<PaginatedVista[]>;
  private readonly fetchColumnas: (uuid: string) => Observable<PaginatedVistaColumn[]>;
  private readonly fetchData: (request: PaginationRequest) => Observable<Pagination<T>>;

  constructor(params: {
    fetchVistas: () => Observable<PaginatedVista[]>;
    fetchColumnas: (uuid: string) => Observable<PaginatedVistaColumn[]>;
    fetchData: (request: PaginationRequest) => Observable<Pagination<T>>;
  }) {
    this.fetchVistas = params.fetchVistas;
    this.fetchColumnas = params.fetchColumnas;
    this.fetchData = params.fetchData;
  }

  public build(): Observable<{
    vistas: PaginatedVista[];
    columnas: PaginatedVistaColumn[];
    paginator: DataSourcePaginator<T>;
  }> {
    return this.fetchVistas().pipe(
      concatMap((vistas) => {
        const defaultVista = vistas[0];
        if (!defaultVista) {
          return throwError(() => new Error('No default vista found'));
        }
        return this.fetchColumnas(defaultVista.uuid).pipe(
          map((columnas) => ({
            vistas,
            columnas,
            paginator: new DataSourcePaginator<T>({
              fetchData: this.fetchData,
              uuidVista: defaultVista.uuid,
            }),
          })),
        );
      }),
    );
  }
}
