import { ChangeDetectionStrategy, Component, computed, inject, input } from '@angular/core';
import { DomSanitizer, SafeUrl } from '@angular/platform-browser';
import { TranslateModule } from '@ngx-translate/core';
import { Message } from 'primeng/message';
import { Button } from 'primeng/button';
import { emptyIcon, errorIcon } from './icons';

@Component({
  selector: 'bod-empty-message',
  imports: [TranslateModule, Message, Button],
  templateUrl: './empty-message.html',
  styleUrl: './empty-message.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class EmptyMessage {
  private readonly sanitizer = inject(DomSanitizer);

  public readonly message = input('shared.emptyMessage.empty');
  public readonly image = input<'empty' | 'error'>('empty');
  public readonly severity = input<
    'success' | 'info' | 'warn' | 'error' | 'secondary' | 'contrast'
  >('info');

  /** URL del icono SVG sanitizada para que Angular permita usarla en [src] de <img> */
  public iconSvg = computed<SafeUrl>(() =>
    this.sanitizer.bypassSecurityTrustUrl(this.image() === 'empty' ? emptyIcon : errorIcon),
  );

  public retryFunction = input<() => void>();

  public goBackFunction = input<() => void>();

  public onGoBack(): void {
    this.goBackFunction()?.();
  }

  public onRetry(): void {
    this.retryFunction()?.();
  }
}
