import { computed, Injectable, signal } from "@angular/core";
import { AuthUser } from "../models";

@Injectable({
  providedIn: 'root',
})
export class AuthState {
  private readonly _authUser = signal<AuthUser | null>(null);

  public authUser = computed(() => this._authUser());
  public isAuthenticated = computed(() => !!this._authUser());

  public setAuthUser(authUser: AuthUser) {
    this._authUser.set(authUser);
  }

  public resetState() {
    this._authUser.set(null);
  }
}
