import { CurrencyPipe, DatePipe, NgTemplateOutlet } from '@angular/common';
import { FormsModule } from '@angular/forms';
import {
  ChangeDetectionStrategy,
  Component,
  TemplateRef,
  computed,
  contentChild,
  contentChildren,
  input,
  signal,
  viewChild,
} from '@angular/core';
import { Table, TableLazyLoadEvent, TableModule } from 'primeng/table';
import { TitleCasePipe } from '@angular/common';
import { MenuItem, MenuItemCommandEvent } from 'primeng/api';
import { MenuModule } from 'primeng/menu';
import { Chip } from 'primeng/chip';
import { SelectButtonModule } from 'primeng/selectbutton';
import { DataViewModule } from 'primeng/dataview';
import { CardModule } from 'primeng/card';
import { DataSourcePaginator } from '../../../utils';
import { LoadStateHandler } from '../../ui/load-state-handler';
import { PaginatedVistaColumn } from '../../../models/paginated-vistas';
import { DataTableCellTemplateDirective } from './data-table-cell-template-directive';
import { ButtonModule, ButtonSeverity } from 'primeng/button';
import { Tooltip } from 'primeng/tooltip';
import { SpeedDialModule } from 'primeng/speeddial';

export interface RowAction<T extends object> extends Omit<MenuItem, 'command'> {
  visible: boolean;
  icon: string;
  label?: string;
  disabled?: boolean;
  tooltip?: string;
  severity?: ButtonSeverity;
  badge?: string;
  command: (event: MenuItemCommandEvent) => void;
}

type RowActionsSplit<T extends object> = {
  visible: RowAction<T>[];
  overflow: RowAction<T>[];
};

/**
 * Contrato mínimo que debe cumplir la fuente de datos de la tabla
 * (p. ej. DataSourcePaginator de @bod/shared).
 */

@Component({
  selector: 'bod-data-table',
  standalone: true,
  imports: [
    FormsModule,
    TableModule,
    TitleCasePipe,
    NgTemplateOutlet,
    Chip,
    DatePipe,
    LoadStateHandler,
    CurrencyPipe,
    SelectButtonModule,
    DataViewModule,
    CardModule,
    ButtonModule,
    Tooltip,
    MenuModule,
    SpeedDialModule,
  ],
  templateUrl: './data-table.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class DataTable<T extends object> {
  /** Fuente de datos (paginator) con items, loading, paginación y lazy load */
  public readonly dataSource = input.required<DataSourcePaginator<T>>();

  /** Definición de columnas (header + entityName para acceder al valor en la fila) */
  public readonly columns = input<PaginatedVistaColumn[]>([]);

  /** Modo de visualización: tabla o cards. */
  public readonly viewMode = signal<'table' | 'cards'>('table');

  public readonly viewModeOptions: Array<{
    label: string;
    value: 'table' | 'cards';
    icon: string;
  }> = [
    { label: 'Tabla', value: 'table', icon: 'pi pi-table' },
    { label: 'Tarjetas', value: 'cards', icon: 'pi pi-th-large' },
  ];

  /** Si se muestra la columna de acciones (primera columna). Por defecto true */
  public readonly showActionsColumn = input<boolean>(true);

  public readonly rowActionsBuilder = input<(row: T) => RowAction<T>[]>(() => []);

  public readonly maxVisibleRowActions = input<number>(3);

  public readonly captionTemplate = contentChild<TemplateRef<unknown>>('caption');

  /** Templates por columna (`column.key`) para sobrescribir el render de la celda. */
  public readonly cellTemplates = contentChildren(DataTableCellTemplateDirective);

  public readonly cellTemplatesByKey = computed(() => {
    const map = new Map<string, TemplateRef<unknown>>();
    for (const t of this.cellTemplates()) {
      map.set(t.bodDataTableCell(), t.templateRef);
    }
    return map;
  });

  public cellTemplateFor(key: string): TemplateRef<unknown> | null {
    return this.cellTemplatesByKey().get(key) ?? null;
  }

  /** Altura del scroll del body (p. ej. '500px'). Por defecto '500px' */
  public readonly scrollHeight = input<string>('500px');

  /** Opciones de filas por página */
  public readonly rowsPerPageOptions = input<number[]>([10, 20, 50]);

  public readonly dt = viewChild<Table>(Table);

  private isRowActionVisible(action: RowAction<T>, row: T): boolean {
    return action.visible !== false;
  }

  private getRowActions(row: T): RowAction<T>[] {
    return (this.rowActionsBuilder()?.(row) ?? []).filter((a) => this.isRowActionVisible(a, row));
  }

  public splitRowActions(row: T): RowActionsSplit<T> {
    const actions = this.getRowActions(row);
    const max = Math.max(0, this.maxVisibleRowActions());
    return {
      visible: actions.slice(0, max),
      overflow: actions.slice(max),
    };
  }

  /** Indica si la fila tiene al menos una acción visible (útil en vista tarjetas). */
  public rowHasActions(row: T): boolean {
    return this.getRowActions(row).length > 0;
  }

  public buildRowActionsMenu(row: T): MenuItem[] {
    const { overflow } = this.splitRowActions(row);
    return overflow.map((action) => ({
      label: action.label || action.tooltip,
      icon: action.icon,
      disabled: action.disabled,
      command: (event) => action.command(event),
    }));
  }

  /** Se usa para decidir si renderizar la columna "Acciones". */
  public readonly hasAnyRowActions = computed(() => {
    if (!this.showActionsColumn()) return false;
    const items = this.dataSource().items();
    const sample = items?.[0];
    if (!sample) return false;
    return this.getRowActions(sample).length > 0;
  });

  public onLazyLoad(event: TableLazyLoadEvent): void {
    this.dataSource().handleTableLazyLoadEvent(event);
  }

  public filterGlobal(value: string, matchMode: string): void {
    this.dt()?.filterGlobal(value, matchMode);
  }
}
