import { inject, Injectable } from '@angular/core';
import { MenuItem } from 'primeng/api';
import { TranslateService } from '@ngx-translate/core';
import { map, merge, Observable, of } from 'rxjs';

@Injectable({
  providedIn: 'root',
})
export class MenuItemsLocalizer {
  private readonly translateService = inject(TranslateService);

  /**
   * Returns an observable of the localized menu.
   * Emits immediately with translated labels and then again whenever the language changes.
   * @param menu - The menu to localize.
   * @returns An observable of the localized menu.
   */
  public getLocalizedMenuItemsObservable(menu: MenuItem[]): Observable<MenuItem[]> {
    const emitLocalized = () => this.translateLabels(menu);
    return merge(of(emitLocalized()), this.translateService.onLangChange.pipe(map(emitLocalized)));
  }

  /**
   * Returns the localized menu.
   * @param menu - The menu to localize.
   * @returns The localized menu.
   */
  public getLocalizedMenuItems(menu: MenuItem[]): MenuItem[] {
    return this.translateLabels(menu);
  }

  private translateLabels(item: MenuItem[]): MenuItem[] {
    return item.map((item) => ({
      ...item,
      label: item.label ? this.translateService.instant(item.label) : undefined,
      items: item.items ? this.translateLabels(item.items) : undefined,
    }));
  }
}
