import {
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChild,
  effect,
  input,
  OnDestroy,
  signal,
} from '@angular/core';
import { NgControl, Validators } from '@angular/forms';
import { Subscription } from 'rxjs';
import { CommonModule } from '@angular/common';
import { FormFieldLabel } from '../form-field-label';
import { FormFieldValidationErrors } from '../form-field-validation-errors';
import { FormFieldControl } from '../form-field-control';
import { Tooltip } from 'primeng/tooltip';
import { TranslateModule } from '@ngx-translate/core';
import { shouldShowValidationErrors } from '../../../../utils';

@Component({
  selector: 'bod-form-field',
  imports: [CommonModule, FormFieldValidationErrors, Tooltip, TranslateModule],
  templateUrl: './form-field.html',
  styleUrl: './form-field.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class FormField implements OnDestroy {
  private ngControlDirective = contentChild<NgControl>(NgControl);
  public innerControl = computed(() => this.ngControlDirective()?.control);
  public shouldShowValidationErrors = signal(false);
  public controlIsRequired = computed(() => {
    return this.innerControl()?.hasValidator(Validators.required);
  });
  public subscription = new Subscription();
  public customValidationMessages = input<Record<string, string>>();

  public formFieldLabel = contentChild(FormFieldLabel);
  public formFieldControl = contentChild(FormFieldControl);

  public inline = input<boolean>(false);
  public showRequiredIndicator = input<boolean>(true);
  public showValidationErrors = input<boolean>(true);

  /**
   * When true (default), reserves space below the control for messages/hint (min-height).
   * When false, height is dynamic and collapses when there is no content.
   */
  public reserveMessagesSpace = input<boolean>(false);

  public constructor() {
    effect(() => {
      const control = this.innerControl();
      if (control) {
        this.subscription.add(
          control.events.subscribe(() => {
            this.shouldShowValidationErrors.set(shouldShowValidationErrors(control));
          }),
        );
        this.subscription.add(
          control.statusChanges.subscribe(() => {
            this.shouldShowValidationErrors.set(shouldShowValidationErrors(control));
          }),
        );
      }
    });
  }

  public ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }
}
