import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  OnDestroy,
  OnInit,
  signal,
} from '@angular/core';
import { AbstractControl } from '@angular/forms';
import { TranslateService } from '@ngx-translate/core';
import { Subscription } from 'rxjs';
import { MessageModule } from 'primeng/message';
import { shouldShowValidationErrors } from '../../../../utils';

@Component({
  selector: 'bod-form-field-validation-errors',
  imports: [MessageModule],
  templateUrl: './form-field-validation-errors.html',
  styleUrl: './form-field-validation-errors.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class FormFieldValidationErrors implements OnDestroy, OnInit {
  private readonly translateService = inject(TranslateService);
  private readonly subscriptions = new Subscription();
  public control = input.required<AbstractControl>();
  public customMessages = input<Record<string, string>>();
  public message = signal('');

  public shouldShow = computed(() => shouldShowValidationErrors(this.control()));

  public ngOnInit(): void {
    this.subscribeToControlStatusChanges();
  }

  public ngOnDestroy(): void {
    this.subscriptions.unsubscribe();
  }

  private clearMessage = (): void => {
    this.message.set('');
  };

  private subscribeToControlStatusChanges(): void {
    const control = this.control();
    if (control) {
      this.updateMessageFromControl(control);
      this.subscriptions.add(
        control.events.subscribe(() => {
          this.updateMessageFromControl(control);
        })
      );
    }
  }

  private updateMessageFromControl(control: AbstractControl): void {
    if (!control.errors) {
      this.clearMessage();
      return;
    }
    const firstErrorKey = Object.keys(control.errors)[0];
    if (!firstErrorKey) {
      this.clearMessage();
      return;
    }
    this.message.set(this.getErrorMessage(firstErrorKey, control.errors[firstErrorKey]));
  }

  private getErrorMessage(
    errorKey: string,
    errorValue: unknown,
    customMessages?: Record<string, string>
  ): string {
    // Check for custom message first
    if (customMessages && customMessages[errorKey]) {
      return customMessages[errorKey];
    }

    // Map common validation errors to translation keys
    const translationKey = this.getTranslationKey(errorKey);

    // Get translation with parameters
    const params = this.getTranslationParams(errorKey, errorValue);

    return this.translateService.instant(translationKey, params);
  }

  private getTranslationParams(errorKey: string, errorValue: unknown): Record<string, unknown> {
    const params: Record<string, unknown> = {};

    switch (errorKey) {
      case 'minlength':
        params['requiredLength'] = (errorValue as { requiredLength: number }).requiredLength;
        params['actualLength'] = (errorValue as { actualLength: number }).actualLength;
        break;
      case 'maxlength':
        params['requiredLength'] = (errorValue as { requiredLength: number }).requiredLength;
        params['actualLength'] = (errorValue as { actualLength: number }).actualLength;
        break;
      case 'min':
        params['min'] = (errorValue as { min: number }).min;
        params['actual'] = (errorValue as { actual: number }).actual;
        break;
      case 'max':
        params['max'] = (errorValue as { max: number }).max;
        params['actual'] = (errorValue as { actual: number }).actual;
        break;
      case 'pattern':
        params['pattern'] = (errorValue as { requiredPattern: string }).requiredPattern;
        break;
    }

    return params;
  }

  private getTranslationKey(errorKey: string): string {
    const errorMap: Record<string, string> = {
      required: 'validation.required',
      email: 'validation.email',
      minlength: 'validation.minlength',
      maxlength: 'validation.maxlength',
      min: 'validation.min',
      max: 'validation.max',
      pattern: 'validation.pattern',
      passwordMatch: 'validation.passwordMatch',
      requiredUppercaseChar: 'validation.requiredUppercaseChar',
      requiredLowercaseChar: 'validation.requiredLowercaseChar',
      requiredNumberChar: 'validation.requiredNumberChar',
      requiredSpecialChar: 'validation.requiredSpecialChar',
    };

    return errorMap[errorKey] || 'validation.generic';
  }
}
