import { computed, signal } from "@angular/core";
import { BehaviorSubject, Observable } from "rxjs";
import { catchError, finalize, tap } from "rxjs/operators";
import {
  LegacyPagination,
  LegacyPaginationRequest,
  LegacyPaginationRequestFilter,
  LegacyPaginatorOptions,
} from "../models";
import { TableLazyLoadEvent } from "primeng/table";



export interface LegacyPaginationFilter extends LegacyPaginationRequestFilter {
  isGlobal?: boolean;
}
export class LegacyDataSourcePaginator<T> {
  private _items = signal<T[]>([]);
  private _loading = signal<boolean>(false);
  private _error = signal<string | null>(null);
  private _totalCount = signal<number>(0);
  private _totalPages = signal<number>(0);
  private _currentPage = signal<number>(1);
  private _pageSize = signal<number>(10);
  private _hasNextPage = signal<boolean>(false);
  private _hasPreviousPage = signal<boolean>(false);
  private _sortBy = signal<string>('');
  private _sortDirection = signal<'asc' | 'desc'>('asc');
  private _filters = signal<LegacyPaginationFilter[][]>([]);
  private _itemsSubject = new BehaviorSubject<LegacyPagination<T>[]>([]);

  public items = this._items.asReadonly();
  public loading = this._loading.asReadonly();
  public error = this._error.asReadonly();
  public totalCount = this._totalCount.asReadonly();
  public totalPages = this._totalPages.asReadonly();
  public currentPage = this._currentPage.asReadonly();
  public pageSize = this._pageSize.asReadonly();
  public hasNextPage = this._hasNextPage.asReadonly();
  public hasPreviousPage = this._hasPreviousPage.asReadonly();
  // public globalSearch = computed(() => (this._filters()['globalSearch'] || '').toString());
  public sortBy = this._sortBy.asReadonly();
  public sortDirection = this._sortDirection.asReadonly();
  public filters = this._filters.asReadonly();
  public pageIndex = computed(() => this.currentPage() - 1);
  public items$ = this._itemsSubject.asObservable();

  private infiniteScroll = false;
  private defaultFilters: LegacyPaginationRequestFilter[] = [];
  private sortTable = '';
  private relaciones: string[] = [];
  protected fetchData: (request: LegacyPaginationRequest) => Observable<LegacyPagination<T>>;

  public filtersApplied = computed(
    () => Object.keys(this.filters()).length > 0
  );

  constructor(options: LegacyPaginatorOptions<T>) {
    this._currentPage.set(options.page ?? 1);
    this._pageSize.set(options.pageSize ?? 10);
    this.infiniteScroll = options.infiniteScroll ?? false;
    this.defaultFilters = options.defaultFilters ?? [];
    this.sortTable = options.sortTable ?? '';
    this.relaciones = options.relaciones ?? [];
    this.fetchData = options.fetchData;

    this._itemsSubject.next([]);
  }

  public clearFilters(): void {
    this._filters.set([]);
    this.clearItems();
    this.loadData(1);
  }

  public applyGlobalSearch(value: string, columns: string[]): void {
    const filters: LegacyPaginationFilter[] = []
    columns.forEach(c => {
      filters.push({
        columna: c,
        tabla: 't',
        operacion: 'like',
        valor: `%${value}%`,
      })
    })
    this.applyFilters(filters);
  }

  public applyFilters(filters: LegacyPaginationFilter[], concat = false) {
    this._filters.update(prev => concat ? [...prev, filters] : [filters])
    this.clearItems();
    this.loadData(1)
  }


  private clearItems(): void {
    this._items.set([]);
    this._itemsSubject.next([]);
  }

  /**
   * Construye un PaginationRequest según el modelo del API (page 0-based, size, parametros, ordenes, filtros).
   */
  private buildRequest(): LegacyPaginationRequest {
    const ordenes =
      this.sortBy().length > 0
        ? [
          {
            tabla: this.sortTable,
            columna: this.sortBy(),
            direccion: this.sortDirection(),
          },
        ]
        : [];

    return {
      page: this.currentPage(),
      size: this.pageSize(),
      parametros: [],
      relaciones: [...this.relaciones],
      ordenes,
      filtros: [[...this.defaultFilters], ...this.filters()],
    };
  }

  public refresh(): void {
    this.loadData();
  }

  /**
   * Get current items value from BehaviorSubject
   */
  public getCurrentItems(): T[] {
    return this._itemsSubject.value as T[];
  }

  public loadNextPage(): void {
    if (this.hasNextPage()) {
      this._currentPage.set(this.currentPage() + 1);
      this.loadData();
    }
  }

  public loadPreviousPage(): void {
    if (this.hasPreviousPage()) {
      this._currentPage.set(this.currentPage() - 1);
      this.loadData();
    }
  }

  public handleTableLazyLoadEvent(event: TableLazyLoadEvent): void {
    if (typeof event.first === 'number' && typeof event.rows === 'number') {
      this._currentPage.set(event.first === 0 ? 1 : event.first / event.rows + 1);
      this._pageSize.set(event.rows);
    }

    // if (typeof event.globalFilter === 'string') {
    //   this._filters.set({ ...this.filters()});
    //   this._currentPage.set(1);
    // } else {
    //   this._filters.set({ ...this.filters()});
    // }

    const sortField = event.sortField;

    if (typeof sortField === 'string') {
      this._sortBy.set(sortField);
      this._sortDirection.set(event.sortOrder === 1 ? 'asc' : 'desc');
    } else {
      this._sortBy.set('');
      this._sortDirection.set('asc');
    }

    this.loadData();
  }

  /**
   * Load data with current pagination settings
   */
  public loadData(page?: number, pageSize?: number): void {
    if (page) this._currentPage.set(page);
    if (pageSize) this._pageSize.set(pageSize);

    this._loading.set(true);
    this._error.set(null);

    const request: LegacyPaginationRequest = this.buildRequest();

    this.fetchData(request)
      .pipe(
        tap((response) => this.handleSuccess(response)),
        catchError((error) => this.handleError(error)),
        finalize(() => this._loading.set(false))
      )
      .subscribe();
  }

  /**
   * Procesa la respuesta Pagination del API (contant, totalElements, totalPages, number, size).
   */
  private handleSuccess(response: LegacyPagination<T>): void {
    const content = response.content ?? [];
    const totalElements = response.totalElements ?? 0;
    const totalPages = response.totalPages ?? 0;
    const pageNumber = response.number ?? 0;
    const size = response.size ?? this.pageSize();

    this.updateItems(content);
    this._totalCount.set(totalElements);
    this._totalPages.set(totalPages);
    this._hasNextPage.set(pageNumber + 1 < totalPages);
    this._hasPreviousPage.set(pageNumber > 0);
    this._currentPage.set(pageNumber + 1);
    this._pageSize.set(size);
    this._error.set(null);
  }

  private updateItems(items: T[]): void {
    // If infinite scroll is enabled, append items only if we're not on page 1
    // On page 1, we should replace items to allow filtering/tab changes
    const newItems =
      this.infiniteScroll && this.currentPage() > 1 ? [...this._items(), ...items] : items;
    this._items.set(newItems);
    this._itemsSubject.next(newItems as LegacyPagination<T>[]);
  }

  /**
   * Handle API error
   */
  private handleError(error: unknown): Observable<never> {
    const err = error as { message?: string; error?: { message?: string } };
    const errorMessage = err?.message || err?.error?.message || 'An error occurred';
    this._error.set(errorMessage);
    this._loading.set(false);
    throw error;
  }
}
