import { FilterMetadata } from "primeng/api";
import { Observable } from "rxjs";

export type PaginationFilter = {
  [key: string]: FilterMetadata | FilterMetadata[] | undefined;
};

export interface MultiSortMeta {
  field: string;
  order: number;
}

export enum PaginationFilterOperation {
  LIKE = 'like',
  EQUAL = '=',
  LESS_THAN = '<',
  GREATER_THAN = '>',
  LESS_THAN_OR_EQUAL = '<=',
  GREATER_THAN_OR_EQUAL = '>=',
}

export interface Pagination<TData> {
  content: TData[];
  totalElements: number;
  totalPages: number;
  number: number;
  size: number;
}

export interface PaginationRequestOrder {
  tabla: string;
  columna: string;
  direccion: 'asc' | 'desc';
}


export interface PaginationRequest {
  first: number;
  rows: number;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  parametros?: Record<string, any>;
  relaciones?: string[];
  multiSortMeta?: MultiSortMeta[];
  filters?: PaginationFilter;
  uuidVista?: string;
}


export interface PaginatorOptions<T> {
  uuidVista?: string;
  page?: number;
  pageSize?: number;
  infiniteScroll?: boolean;
  defaultFilters?: PaginationFilter;
  /** Tabla usada al construir ordenes cuando se usa sortBy/sortDirection */
  sortTable?: string;
  relaciones?: string[];
  fetchData(request: PaginationRequest): Observable<Pagination<T>>;
}
