import { DatePipe } from '@angular/common';
import { ChangeDetectorRef, DestroyRef, inject, Pipe, PipeTransform } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { TranslateService } from '@ngx-translate/core';

@Pipe({
  name: 'localizedDate',
  standalone: true,
  pure: false,
})
export class LocalizedDatePipe implements PipeTransform {
  private readonly translateService = inject(TranslateService);
  private readonly changeDetectorRef = inject(ChangeDetectorRef);
  private readonly destroyRef = inject(DestroyRef);

  public constructor() {
    this.translateService.onLangChange
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(() => this.changeDetectorRef.markForCheck());
  }

  public transform(value: Date | string | number, format = 'medium'): string {
    if (!value) return '';

    // Get current language from translate service
    const currentLang = this.translateService.getCurrentLang() || 'en-US';

    // Create DatePipe with the correct locale
    const datePipe = new DatePipe(currentLang);

    // Convert value to Date if it's a string or number
    const dateValue =
      typeof value === 'string' || typeof value === 'number' ? new Date(value) : value;

    return datePipe.transform(dateValue, format, Intl.DateTimeFormat().resolvedOptions().timeZone, currentLang) || '';
  }
}
